={
  "model": "mistral",
  "prompt": "Answer this: There are no quota seats.",
  "stream": false
}

parameters.jsCode:
const userQuestion = $input.first().json?.body?.query || '';

const faqs = [
  {"q": "quota", "a": "There are no quota seats."},
  {"q": "MBBS", "a": "Admissions in NSHS will be purely on merit, based upon the MDCAT conducted by NUMS."},
  {"q": "open merit ACT", "a": "Yes, on the basis of NET / MDCAT Score and required ACT Score."},
  {"q": "ICS engineering", "a": "Yes, candidates having Physics, Mathematics and Computer Science are eligible for Engineering programs."},
  {"q": "pre-medical engineering", "a": "Candidate can apply but must provide additional math result with passing marks and 60% HSSC marks."},
  {"q": "pre-medical computer science", "a": "Yes, but must clear Mathematics courses of 6 credit hours within one year."},
  {"q": "foreign BSHND", "a": "Foreign students are eligible to apply on the basis of NET-Applied Sciences / NUMS-MDCAT / ACT Test."},
  {"q": "foreign MBBS NSHS", "a": "Foreign students can apply on basis of NUMS MDCAT, SAT-II or foreign MCAT / UCAT score."},
  {"q": "computing arts", "a": "Yes, if you have Mathematics as mandatory subject in HSSC / A level."},
  {"q": "apply multiple programme", "a": "Yes, if you meet the eligibility criteria."},
  {"q": "rechecking entry test", "a": "Yes, within 5 days with fee of Rs.500/- as bank draft in favour of NUST."},
  {"q": "copy entry test result", "a": "Yes, obtain result details from link available on NUST website."},
  {"q": "sample test papers", "a": "Yes, Mock Test available on NUST website www.ugadmissions.nust.edu.pk under Sample Test link."},
  {"q": "expatriate students", "a": "Yes if you reside outside Pakistan with Pakistani passport or dual nationality."},
  {"q": "pick drop facility", "a": "Yes for students of Rawalpindi and Islamabad only with specified routes for separate charges."},
  {"q": "scholarship", "a": "Yes, students with minimum GPA 3.5 out of 4.0 are eligible for financial assistance."},
  {"q": "UG disciplines academic", "a": "Visit: https://nust.edu.pk/admissions/undergraduates/academic-qualification-required-for-different-ug-progammes/"},
  {"q": "expatriate dual nationality", "a": "Expatriate with dual nationality can opt for both NET and SAT on national and international seats."},
  {"q": "BSHND application", "a": "Apply online at: http://nshsadmission.nust.edu.pk/hnd/"},
  {"q": "MBBS application NSHS", "a": "Visit: https://nust.edu.pk/admissions/NSHS/how-to-apply/"},
  {"q": "1Link payment", "a": "Use 17-digit 1Bill Invoice number to pay via 1Link through Mobile App, Online Banking, ATM, Easy Paisa, Jazz Cash."},
  {"q": "application fee payment", "a": "Submit through 1Link (1Bill Invoice Number) or Credit Card."},
  {"q": "allied programmes NSHS", "a": "Currently NSHS offers BS Human Nutrition and Dietetics (BSHND)."},
  {"q": "Pakistani foreign passport expatriate", "a": "If no Pakistani nationality like CNIC, apply as international student on NET or ACT/SAT basis."},
  {"q": "foreigner admission NUST", "a": "If eligible, apply on NET or ACT / SAT basis. Visit: https://nust.edu.pk/admissions/undergraduates/international-students/"},
  {"q": "Urdu Islamiyat Pakistan Studies equivalence", "a": "No, not compulsory per IBCC rules. Visit: https://ibcc.edu.pk/rules-for-equivalence/"},
  {"q": "final year A Level apply", "a": "Yes, evaluated on O levels basis but provide A level certificate within 15 days of result."},
  {"q": "missed entry test retake", "a": "No, normally not given another chance unless extreme emergency case by case."},
  {"q": "DAE background programmes", "a": "Must have 60% marks in Matric and DAE. Check PEC approved Engineering programmes on NUST website."},
  {"q": "selected 3 merits", "a": "You have option to retain any one seat of your own choice."},
  {"q": "ACT SAT entry test", "a": "Not required for ACT/SAT basis, but can opt for NET in addition for both streams."},
  {"q": "less 60% FSc part-1", "a": "Yes for merit generation, but must have 60% or more in FSc complete result when joining."},
  {"q": "equivalence certificate", "a": "Yes, from IBCC Pakistan for non-FSc stream candidates with minimum 60% marks."},
  {"q": "migration NUST", "a": "Yes after completion of first year and before final year for good academic record."},
  {"q": "age limit admission", "a": "No age limit for Undergraduate Admission."},
  {"q": "installment tuition", "a": "Yes, quarterly (0%), six monthly (2%), or annual (4%) basis as per PM&DC regulations."},
  {"q": "negative marking", "a": "No negative marking in NUST Entry Test."},
  {"q": "name differs documents", "a": "Get name changed on CNIC and Passport to match Matric or O level SSC from IBCC."},
  {"q": "NSHS university affiliated", "a": "NSHS is constituent school of NUST. MBBS degree awarded by NUST."},
  {"q": "university fees revised", "a": "Usually announced once yearly for following academic year, subject to change."},
  {"q": "UG programmes NUST", "a": "Visit NUST website for complete list of offered UG programmes."},
  {"q": "salient features UG admissions", "a": "Visit NUST admissions website for detailed salient features."},
  {"q": "entry test subjects", "a": "Visit: https://nust.edu.pk/admissions/undergraduates/subjects-included-in-net-with-weightings/"},
  {"q": "ACT SAT basis", "a": "Any candidate with required ACT/SAT scores for prescribed disciplines."},
  {"q": "documents required admission", "a": "CNIC / Form B or NICOP mandatory. Documents needed for verification of selected candidates."},
  {"q": "gap year repeater", "a": "Considered as normal candidates with no penalization in merit generation."},
  {"q": "BSHND criteria", "a": "Visit: https://nust.edu.pk/admissions/alliedprogram/admission-criteria/"},
  {"q": "BSHND schedule", "a": "Visit: https://nust.edu.pk/admissions/alliedprogram/dates-to-remember/"},
  {"q": "application fee", "a": "Pakistani Rs. 5,000 or USD 40; Foreign Rs. 10,000 or USD 80. ACT/SAT: National Rs. 5,000; International Rs. 10,000."},
  {"q": "ACT SAT score deadline", "a": "25 July 2025. ACT code: 2915, SAT code: 2790. Valid for 2 years."},
  {"q": "ACT SAT scores required", "a": "Visit: https://nust.edu.pk/admissions/undergraduates/applying-on-the-basis-of-scholastic-aptitude-test-sat/"},
  {"q": "test duration MCQs", "a": "200 MCQs in 3 hours (180 minutes)."},
  {"q": "eligibility programmes", "a": "Visit: https://nust.edu.pk/admissions/undergraduates/eligibility-criteria-for-ug-programmes/"},
  {"q": "MBBS fee NSHS", "a": "Visit: https://nust.edu.pk/admissions/NSHS/fee-structure/"},
  {"q": "BSHND fee", "a": "Visit: https://nust.edu.pk/admissions/alliedprogram/fee-structure-bshnd/"},
  {"q": "UG fee structure", "a": "Visit: https://nust.edu.pk/admissions/fee-structure/undergraduate-financial-matters/"},
  {"q": "merit criteria MBBS", "a": "Visit: https://nust.edu.pk/admissions/NSHS/merit-generation-criteria-mbbs/"},
  {"q": "merit BSHND", "a": "NET/MDCAT/ACT 75%, HSSC 15%, SSC 10%. ACT International: 100% ACT."},
  {"q": "entry test syllabus", "a": "Based on SSC/HSSC level studies. MCQs with 4 options. English on SAT pattern."},
  {"q": "test venues NET", "a": "Islamabad: NUST Exam Hall Main Campus H-12. Quetta: Balochistan Campus. Karachi/Gilgit: Per admit card."},
  {"q": "NET result announcement", "a": "Computer-based within 24 hours, paper-based within 5-7 working days."},
  {"q": "NSHS admission advertised", "a": "In electronic and print media per NUMS and PM&DC policy."},
  {"q": "MBBS classes start", "a": "As per PM&DC guidelines."},
  {"q": "NSHS location", "a": "NUST main campus, sector H-12, Islamabad. Maps: https://rb.gy/f6a26"},
  {"q": "BSHND tests", "a": "Open Merit: NET-Applied Sciences, NUMS MDCAT, National MDCAT. ACT: ACT Test."},
  {"q": "MDCAT NSHS", "a": "NUMS MDCAT only."},
  {"q": "NET fee exemption", "a": "Top 3 position holders in HSSC from various boards."},
  {"q": "entry test queries contact", "a": "Phone: +92 51-90856878"},
  {"q": "quarterly semi-annual payment", "a": "Yes, MBBS admission confirmed with quarterly or six-monthly installments."},
  {"q": "hostel MBBS", "a": "Yes for boys and girls per NUST SoP. Apply on selection confirmation."},
  {"q": "fee deposit refundable", "a": "Only security deposit refunded. Admission Processing Fee non-refundable."}
];

let bestAnswer = "No matching FAQ found. Please rephrase your question.";
let bestScore = 0;

for (let faq of faqs) {
  let score = 0;
  const questionLower = userQuestion.toLowerCase();
  const faqQLower = faq.q.toLowerCase();

  // Check each word
  const questionWords = questionLower.split(/\s+/);

  for (let word of questionWords) {
    if (word.length > 2) {
      // Exact word match in FAQ question
      if (faqQLower.split(/\s+/).includes(word)) {
        score += 2;
      }
      // Partial word match
      else if (faqQLower.includes(word)) {
        score += 1;
      }
    }
  }

  if (score > bestScore) {
    bestScore = score;
    bestAnswer = faq.a;
  }
}

return { json: { answer: bestAnswer } };
